<?php include __DIR__ . '/../../includes/header.php'; require_permission('auditoria.ver'); $rows=$pdo->query("SELECT b.*, CONCAT(u.nombres,' ',u.apellidos) usuario FROM bitacora b LEFT JOIN usuarios u ON u.id_usuario=b.id_usuario ORDER BY b.fecha_hora DESC LIMIT 200")->fetchAll(); ?>
<h1>Bitácora de auditoría</h1><div class="card"><table><tr><th>ID</th><th>Usuario</th><th>Acción</th><th>Descripción</th><th>IP</th><th>Fecha</th></tr><?php foreach($rows as $r): ?><tr><td><?= $r['id_evento'] ?></td><td><?= e($r['usuario']??'Sistema') ?></td><td><?= e($r['accion']) ?></td><td><?= e($r['descripcion']) ?></td><td><?= e($r['ip_origen']) ?></td><td><?= e($r['fecha_hora']) ?></td></tr><?php endforeach; ?></table></div><?php include __DIR__ . '/../../includes/footer.php'; ?>
